	@Test
	void structuredTelemetryCapturesMatchedAndSkippedRules() throws Exception {
		RuleRegistry registry = RuleRegistry.builder()
				.add(new TestImplementationRule("matching-implementation", 1.0d))
				.add(new NeverMatchingRule("never-match"))
				.build();
		CascadesTelemetry.Recording telemetry = new CascadesTelemetry.Recording(64);
		CascadesPlanner planner = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry,
				telemetry);

		planner.optimize(pattern("s", "p", "o"), OptimizationGoal.root());

		Map<String, Object> trace = structuredTrace(telemetry);
		List<Map<String, Object>> ruleEvaluations = traceList(trace, "ruleEvaluations");
		assertTrue(ruleEvaluations.stream()
				.anyMatch(event -> "matching-implementation".equals(event.get("ruleId"))
						&& "matched".equals(event.get("status"))),
				"Expected structured trace to record the rule that matched: " + trace);
		assertTrue(ruleEvaluations.stream()
				.anyMatch(event -> "never-match".equals(event.get("ruleId"))
						&& "not_matched".equals(event.get("status"))),
				"Expected structured trace to record rules that were not run because they did not match: " + trace);

		List<Map<String, Object>> alternatives = traceList(trace, "alternatives");
		assertTrue(alternatives.stream()
				.anyMatch(event -> "matching-implementation".equals(event.get("ruleId"))
						&& "considered".equals(event.get("status"))),
				"Expected structured trace to record considered alternatives: " + trace);
		assertFalse(traceList(trace, "winners").isEmpty(),
				"Expected structured trace to record the chosen winner: " + trace);
	}

	@Test
	void missingInputWinnerTraceIdentifiesFailedInputGoal() {
		Projection projection = new Projection(pattern("s", "p", "o"), projection("o"), false);
		RuleRegistry registry = RuleRegistry.builder()
				.add(new StandardCascadesRules.GenericImplementationRule())
				.build();
		CascadesTelemetry.Recording telemetry = new CascadesTelemetry.Recording(32);
		CascadesPlanner planner = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry,
				telemetry);
		PhysicalProperties excludedChildShape = PhysicalProperties.builder()
				.boundVars(Set.of("s"))
				.build();
		OptimizationGoal goal = new OptimizationGoal(PhysicalProperties.ANY, OptimizationGoal.BAG_SEMANTICS,
				OptimizationGoal.CostPolicy.EXACT, CostVector.INFINITE, Set.of(excludedChildShape),
				OptimizationGoal.SearchMode.EXACT, Long.MAX_VALUE, Integer.MAX_VALUE);

		planner.optimize(projection, goal);

		String trace = String.join("\n", telemetry.trace());
		assertTrue(trace.contains("reason=missing-input-winner"), trace);
		assertTrue(trace.contains("inputIndex=0"), trace);
		assertTrue(trace.contains("inputGroup="), trace);
		assertTrue(trace.contains("inputGoal="), trace);
	}

	@Test
	void joinRightGoalIgnoresOptionalOnlyLeftBindings() {
		StatementPattern mandatoryLeft = pattern("s", "required", "requiredValue");
		StatementPattern optionalLeft = pattern("s", "optional", "maybe");
		StatementPattern right = pattern("maybe", "right", "value");
		Join join = new Join(new LeftJoin(mandatoryLeft, optionalLeft), right);
		RecordingImplementationRule implementation = new RecordingImplementationRule("right");
		CascadesPlanner planner = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()),
				RuleRegistry.builder().add(implementation).build(), CascadesTelemetry.NO_OP);

		planner.optimize(join, OptimizationGoal.root());

		assertFalse(implementation.observedBoundVars.isEmpty(), "Expected the test rule to observe the JOIN RHS");
		assertFalse(implementation.observedBoundVars.stream().anyMatch(boundVars -> boundVars.contains("maybe")),
				"JOIN RHS must not inherit nullable OPTIONAL bindings as assured bound variables: "
						+ implementation.observedBoundVars);
	}

