	private static CostVector exactCost(double rowsAndWork) {
		return new CostVector(rowsAndWork, rowsAndWork, 0.0d, 0.0d, 0.0d, 1.0d, 1.0d, 1.0d, 1.0d,
				0.0d, 1.0d, 1.0d);
	}

	private static final class RecordingImplementationRule implements CascadesRule {
		private final String predicateName;
		private final List<Set<String>> observedBoundVars = new ArrayList<>();

		private RecordingImplementationRule(String predicateName) {
			this.predicateName = predicateName;
		}

		@Override
		public String id() {
			return "recording-implementation";
		}

		@Override
		public RuleKind kind() {
			return RuleKind.IMPLEMENTATION;
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return expression.logical();
		}

		@Override
		public int promise(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return 1;
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			TupleExpr tupleExpr = expression.tupleExpr();
			if (tupleExpr instanceof StatementPattern statementPattern
					&& predicateName.equals(statementPattern.getPredicateVar().getName())) {
				observedBoundVars.add(goal == null ? Set.of() : goal.requiredProperties().boundVars());
			}
			CostVector cost = new CostVector(1.0d, 1.0d, 0.0d, 0.0d, 0.0d, 1.0d, 1.0d, 1.0d, 1.0d,
					0.0d, 1.0d, 1.0d);
			EstimateSnapshot estimate = new EstimateSnapshot("test-planner", "recording-implementation",
					"alternative_ranking", 1.0d, 1.0d, cost, Map.of(), Map.of());
			RuleProof proof = proof(expression, goal, context);
			PhysicalProperties delivered = PhysicalProperties.builder()
					.boundVars(tupleExpr == null ? Set.of() : tupleExpr.getBindingNames())
					.build();
			return List.of(RuleApplication.physical(expression.groupId(), tupleExpr.clone(), delivered, cost, proof,
					id(), estimate));
		}

		@Override
		public RuleProof proof(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			return new RuleProof(id(), RuleKind.IMPLEMENTATION, OptimizationGoal.BAG_SEMANTICS, Set.of("test"),
					"recording implementation");
		}
	}
